import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const l=JSON.parse('{"title":"Account Hub Overview","description":"","frontmatter":{"title":"Account Hub Overview","slug":"account-hub-overview"},"headers":[],"relativePath":"account-hub/account-hub-overview.md","filePath":"account-hub/account-hub-overview.md"}'),o={name:"account-hub/account-hub-overview.md"};function r(s,e,c,u,p,d){return t(),n("div",null,[...e[0]||(e[0]=[i('<p>Welcome to Branch&#39;s <strong>Account Hub</strong>, your resource for managing your Branch account, configuring settings, and administering user access across your organization.</p><h2 id="what-is-account-hub" tabindex="-1">What is Account Hub? <a class="header-anchor" href="#what-is-account-hub" aria-label="Permalink to &quot;What is Account Hub?&quot;">​</a></h2><p>Account Hub is a dedicated documentation workspace designed for account administrators, team managers, and users responsible for configuring and maintaining Branch settings. Whether you&#39;re setting up a new account, managing user permissions, or configuring link settings, you&#39;ll find step-by-step guides and best practices here to help manage your Branch implementation.</p><p>This hub focuses on account administration and configuration, from initial setup and app settings to user management, security, and billing.</p><h2 id="what-s-inside" tabindex="-1">What&#39;s inside <a class="header-anchor" href="#what-s-inside" aria-label="Permalink to &quot;What&#39;s inside&quot;">​</a></h2><p><a href="./get-started-account-hub.html">Get Started</a></p><p>New to managing a Branch account? Start here to understand account setup, navigation, and key administrative features.</p><p><a href="./new-branch.html">New Branch</a></p><p>Learn about the latest platform updates, new features, and improvements to Branch&#39;s account management capabilities. Note that these updates are being rolled out to customers in phases.</p><p><a href="./app-settings.html">App Settings</a></p><p>Configure your app-level settings including attribution windows, add additional apps to your account, and manage app-specific configurations.</p><p><a href="./link-settings.html">Link Settings</a></p><p>Set up and customize your link configurations, manage link domains, and troubleshoot formatting errors.</p><p><a href="./user-accounts-and-permissions.html">User Accounts and Permissions</a></p><p>Manage team member access, assign roles and permissions, and control who can view and edit different aspects of your Branch account.</p><p><a href="./sso.html">SSO</a></p><p>Configure single sign-on for your organization to streamline user authentication and enhance account security.</p><p><a href="./testing-and-monitoring.html">Testing and Monitoring</a></p><p>Monitor account activity with Liveview, manage test devices, find device IDs, and set up notification and alerting systems to stay informed about important events.</p><p><a href="./data-privacy.html">Data Privacy</a></p><p>Manage privacy settings, configure data obfuscation, understand third-party integrations and GDPR compliance, minimize data sent to Branch, and review data retention policies and SDK privacy controls.</p><p><a href="./billing.html">Billing</a></p><p>Manage your subscription, view billing information, and update payment methods for your Branch account.</p><p><a href="./additional-resources.html">Additional Resources</a></p><p>Access support resources including how to submit tickets, information about professional services, and guides to help you get the most from Branch support.</p><p><a href="./release-notes.html">Release Notes</a></p><p>Stay updated on the latest changes, improvements, and new features released to the Branch platform.</p><h2 id="how-to-navigate" tabindex="-1">How to navigate <a class="header-anchor" href="#how-to-navigate" aria-label="Permalink to &quot;How to navigate&quot;">​</a></h2><p>Use the left sidebar to browse topics, or use the search function (CMD+K) to quickly find specific information. Each section contains configuration guides, administrative instructions, and best practices to help you manage your Branch account effectively.</p><p>Article folders are organized by administrative function, making it easy to find the settings and tools you need to configure and maintain your account.</p><h2 id="need-other-resources" tabindex="-1">Need other resources? <a class="header-anchor" href="#need-other-resources" aria-label="Permalink to &quot;Need other resources?&quot;">​</a></h2><p>Account Hub focuses on account administration and configuration. For campaign creation and optimization, visit <a href="./marketer-hub-overview.html">Marketer Hub</a>. For technical implementation and SDK integration, visit <a href="./developer-hub-overview.html">Developer Hub</a>.</p>',32)])])}const m=a(o,[["render",r]]);export{l as __pageData,m as default};
